  `MieDNI` INT NOT NULL COMMENT 'DNI Miembro [FK → H6M_PERSONA] (PK2)',
  `CabFecIni` DATE NOT NULL COMMENT 'Fecha inicio en el grupo familiar',
  `CabFecFin` DATE NULL DEFAULT NULL COMMENT 'Fecha fin – NULL si sigue activo',
  `CabEstReg` CHAR(1) NOT NULL DEFAULT '1' COMMENT 'Estado registro',
  PRIMARY KEY (`CabDNI`, `MieDNI`),
  INDEX `IDX_CAB_miembro` (`MieDNI` ASC) VISIBLE,
  CONSTRAINT `FK_CAB_CABEZA`
    FOREIGN KEY (`CabDNI`)
    REFERENCES `catastro_db`.`h6m_persona` (`PerDNI`)
    ON DELETE RESTRICT
    ON UPDATE CASCADE,
  CONSTRAINT `FK_CAB_MIEMBRO`
    FOREIGN KEY (`MieDNI`)
    REFERENCES `catastro_db`.`h6m_persona` (`PerDNI`)
    ON DELETE RESTRICT
    ON UPDATE CASCADE)
ENGINE = InnoDB
DEFAULT CHARACTER SET = utf8mb4
COLLATE = utf8mb4_spanish_ci
COMMENT = 'Relación reflexiva Persona-Cabeza de Familia – reemplaza FK directa en H6M_PERSONA';


-- -----------------------------------------------------
-- Table `catastro_db`.`h7m_familia`
-- -----------------------------------------------------
DROP TABLE IF EXISTS `catastro_db`.`h7m_familia` ;

CREATE TABLE IF NOT EXISTS `catastro_db`.`h7m_familia` (
  `FamCod` INT NOT NULL AUTO_INCREMENT COMMENT 'Código Familia – PK (N,8)',
  `FamCab` INT NOT NULL COMMENT 'Cabeza de Familia [FK → H6M_PERSONA]',
  `FamNom` VARCHAR(60) NOT NULL COMMENT 'Apellido/denominación familiar (A,60)',
  `FamViv` VARCHAR(10) NULL DEFAULT NULL COMMENT 'Vivienda del grupo [FK → C3M_VIVIENDA] NULL=sin asignar',
  `FamNumMiem` SMALLINT NOT NULL DEFAULT '1' COMMENT 'Número de miembros (>0)',
  `FamEstReg` CHAR(1) NOT NULL DEFAULT '1' COMMENT 'Estado registro',
  PRIMARY KEY (`FamCod`),
  INDEX `IDX_FAM_cab` (`FamCab` ASC) VISIBLE,
  INDEX `IDX_FAM_viv` (`FamViv` ASC) VISIBLE,
  CONSTRAINT `FK_FAM_CAB`
    FOREIGN KEY (`FamCab`)
    REFERENCES `catastro_db`.`h6m_persona` (`PerDNI`)
    ON DELETE RESTRICT
    ON UPDATE CASCADE,
  CONSTRAINT `FK_FAM_VIV`
    FOREIGN KEY (`FamViv`)
    REFERENCES `catastro_db`.`c3m_vivienda` (`VivCod`)
    ON DELETE SET NULL
    ON UPDATE CASCADE)
ENGINE = InnoDB
DEFAULT CHARACTER SET = utf8mb4
COLLATE = utf8mb4_spanish_ci
COMMENT = 'Maestro Familia – FamViv nullable para carga masiva';


-- -----------------------------------------------------
-- Table `catastro_db`.`p9m_escala_tributo`
-- -----------------------------------------------------
DROP TABLE IF EXISTS `catastro_db`.`p9m_escala_tributo` ;

CREATE TABLE IF NOT EXISTS `catastro_db`.`p9m_escala_tributo` (
  `EscCod` VARCHAR(4) NOT NULL COMMENT 'Código escala (A,4) Ej: E01',
  `EscVig` YEAR NOT NULL COMMENT 'Año de vigencia (>2000) – PK2',
  `EscNom` VARCHAR(40) NOT NULL COMMENT 'Nombre descriptivo (A,40)',
  `EscDesc` VARCHAR(200) NULL DEFAULT NULL COMMENT 'Criterio de clasificación (A,200)',
  `EscIngMin` DECIMAL(10,2) NOT NULL DEFAULT '0.00' COMMENT 'Límite inferior de ingreso mensual S/ (>=0)',
  `EscIngMax` DECIMAL(10,2) NOT NULL COMMENT 'Límite superior de ingreso mensual S/ (>Min)',
  `EscPorTrib` DECIMAL(5,2) NULL DEFAULT NULL COMMENT '% del valor catastral – exclusivo con EscMonFij',
  `EscMonFij` DECIMAL(10,2) NULL DEFAULT NULL COMMENT 'Monto fijo anual S/ – exclusivo con EscPorTrib',
  `EscEstReg` CHAR(1) NOT NULL DEFAULT '1' COMMENT 'Estado registro',
  PRIMARY KEY (`EscCod`, `EscVig`),
  INDEX `IDX_ESC_cod` (`EscCod` ASC) VISIBLE,
  INDEX `IDX_ESC_vig` (`EscVig` ASC) VISIBLE)
ENGINE = InnoDB
DEFAULT CHARACTER SET = utf8mb4
COLLATE = utf8mb4_spanish_ci
COMMENT = 'Escala Tributaria – PK (EscCod+EscVig) para versionado anual';


-- -----------------------------------------------------
-- Table `catastro_db`.`h8m_propietario`
-- -----------------------------------------------------
DROP TABLE IF EXISTS `catastro_db`.`h8m_propietario` ;

CREATE TABLE IF NOT EXISTS `catastro_db`.`h8m_propietario` (
  `ProCod` INT NOT NULL AUTO_INCREMENT COMMENT 'Código Propietario – PK (N,8)',
  `ProPer` INT NOT NULL COMMENT 'Persona [FK → H6M_PERSONA]',
  `ProViv` VARCHAR(10) NULL DEFAULT NULL COMMENT 'Vivienda principal [FK → C3M_VIVIENDA] NULL=sin asignar',
  `ProEscCod` VARCHAR(4) NULL DEFAULT NULL COMMENT 'Código escala [FK → P9M_ESCALA_TRIBUTO] (A,4)',
  `ProEscVig` YEAR NULL DEFAULT NULL COMMENT 'Año vigencia escala [FK → P9M_ESCALA_TRIBUTO]',
  `ProFecCla` DATE NULL DEFAULT NULL COMMENT 'Fecha de clasificación de escala',
  `ProEstReg` CHAR(1) NOT NULL DEFAULT '1' COMMENT 'Estado registro',
  PRIMARY KEY (`ProCod`),
  INDEX `IDX_PROP_per` (`ProPer` ASC) VISIBLE,
  INDEX `IDX_PROP_viv` (`ProViv` ASC) VISIBLE,
  INDEX `IDX_PROP_esc` (`ProEscCod` ASC, `ProEscVig` ASC) VISIBLE,
  CONSTRAINT `FK_PROP_ESC`
    FOREIGN KEY (`ProEscCod` , `ProEscVig`)
    REFERENCES `catastro_db`.`p9m_escala_tributo` (`EscCod` , `EscVig`)
    ON DELETE SET NULL
    ON UPDATE CASCADE,
  CONSTRAINT `FK_PROP_PER`
    FOREIGN KEY (`ProPer`)
    REFERENCES `catastro_db`.`h6m_persona` (`PerDNI`)
    ON DELETE RESTRICT
    ON UPDATE CASCADE,
  CONSTRAINT `FK_PROP_VIV`
    FOREIGN KEY (`ProViv`)
    REFERENCES `catastro_db`.`c3m_vivienda` (`VivCod`)
    ON DELETE SET NULL
    ON UPDATE CASCADE)
ENGINE = InnoDB
DEFAULT CHARACTER SET = utf8mb4
COLLATE = utf8mb4_spanish_ci
COMMENT = 'Maestro Propietario – ProViv nullable para carga masiva';


-- -----------------------------------------------------
-- Table `catastro_db`.`h8m_prop_vivienda`
-- -----------------------------------------------------
DROP TABLE IF EXISTS `catastro_db`.`h8m_prop_vivienda` ;

CREATE TABLE IF NOT EXISTS `catastro_db`.`h8m_prop_vivienda` (
  `PvPrp` INT NOT NULL COMMENT 'Propietario [FK → H8M_PROPIETARIO] (PK1)',
  `PvViv` VARCHAR(10) NOT NULL COMMENT 'Vivienda [FK → C3M_VIVIENDA] (PK2)',
  `PvFecIni` DATE NOT NULL COMMENT 'Fecha inicio de propiedad (PK3)',
  `PvFecFin` DATE NULL DEFAULT NULL COMMENT 'Fecha fin – NULL si sigue activo',
  `PvTitulo` VARCHAR(20) NULL DEFAULT NULL COMMENT 'Nº Título de propiedad (A,20)',
  `PvEstReg` CHAR(1) NOT NULL DEFAULT '1' COMMENT 'Estado registro',
  PRIMARY KEY (`PvPrp`, `PvViv`, `PvFecIni`),
  INDEX `IDX_PV_viv` (`PvViv` ASC) VISIBLE,
  INDEX `IDX_PV_activo` (`PvEstReg` ASC, `PvFecFin` ASC) VISIBLE,
  CONSTRAINT `FK_PV_PROP`
    FOREIGN KEY (`PvPrp`)
    REFERENCES `catastro_db`.`h8m_propietario` (`ProCod`)
    ON DELETE RESTRICT
    ON UPDATE CASCADE,
  CONSTRAINT `FK_PV_VIV`
    FOREIGN KEY (`PvViv`)
    REFERENCES `catastro_db`.`c3m_vivienda` (`VivCod`)
    ON DELETE RESTRICT
    ON UPDATE CASCADE)
ENGINE = InnoDB
DEFAULT CHARACTER SET = utf8mb4
COLLATE = utf8mb4_spanish_ci
COMMENT = 'Asociativa Propietario-Vivienda – PK incluye FecIni para historial de propiedad';


-- -----------------------------------------------------
-- Table `catastro_db`.`pat_tributo_cab`
-- -----------------------------------------------------
DROP TABLE IF EXISTS `catastro_db`.`pat_tributo_cab` ;

CREATE TABLE IF NOT EXISTS `catastro_db`.`pat_tributo_cab` (
  `TriCod` INT NOT NULL AUTO_INCREMENT COMMENT 'Código Tributo – PK (N,6)',
  `TriPro` INT NOT NULL COMMENT 'Propietario [FK → H8M_PROPIETARIO]',
  `TriAnio` YEAR NOT NULL COMMENT 'Año del tributo (>2000)',
  `TriMonCal` DECIMAL(14,2) NULL DEFAULT '0.00' COMMENT 'Monto calculado S/',
  `TriMonPag` DECIMAL(14,2) NULL DEFAULT '0.00' COMMENT 'Monto pagado S/',
  `TriFecVen` DATE NULL DEFAULT NULL COMMENT 'Fecha de vencimiento',
  `TriFecPag` DATE NULL DEFAULT NULL COMMENT 'Fecha de pago',
  `TriObs` VARCHAR(200) NULL DEFAULT NULL COMMENT 'Observaciones (A,200)',
  `TriEstReg` CHAR(1) NOT NULL DEFAULT '1' COMMENT 'Estado registro [0=pagado]',
  PRIMARY KEY (`TriCod`),
  UNIQUE INDEX `UQ_TRI_PRO_ANIO` (`TriPro` ASC, `TriAnio` ASC) VISIBLE,
  INDEX `IDX_TRI_pro` (`TriPro` ASC) VISIBLE,
  INDEX `IDX_TRI_anio` (`TriAnio` ASC) VISIBLE,
  INDEX `IDX_TRI_est` (`TriEstReg` ASC, `TriAnio` ASC) VISIBLE,
  CONSTRAINT `FK_TRI_PROP`
    FOREIGN KEY (`TriPro`)
    REFERENCES `catastro_db`.`h8m_propietario` (`ProCod`)
    ON DELETE RESTRICT
    ON UPDATE CASCADE)
ENGINE = InnoDB
DEFAULT CHARACTER SET = utf8mb4
COLLATE = utf8mb4_spanish_ci
COMMENT = 'Tributo Cabecera – UNIQUE (TriPro+TriAnio) previene duplicados en carga masiva';


-- -----------------------------------------------------
-- Table `catastro_db`.`pam_historial_tributario`
-- -----------------------------------------------------
DROP TABLE IF EXISTS `catastro_db`.`pam_historial_tributario` ;

CREATE TABLE IF NOT EXISTS `catastro_db`.`pam_historial_tributario` (
  `HisCod` INT NOT NULL AUTO_INCREMENT COMMENT 'Código Historial – PK (N,8)',
  `HisTri` INT NOT NULL COMMENT 'Tributo archivado [FK → PAT_TRIBUTO_CAB]',
  `HisAnio` YEAR NOT NULL COMMENT 'Año del tributo (>2000)',
  `HisMonCal` DECIMAL(14,2) NOT NULL DEFAULT '0.00' COMMENT 'Monto calculado al archivar S/',
  `HisMonPag` DECIMAL(14,2) NOT NULL DEFAULT '0.00' COMMENT 'Monto pagado al archivar S/',
  `HisFecPag` DATE NULL DEFAULT NULL COMMENT 'Fecha de pago definitivo',
  `HisFecArch` DATE NOT NULL COMMENT 'Fecha de archivado',
  `HisObs` VARCHAR(200) NULL DEFAULT NULL COMMENT 'Observaciones (A,200)',
  `HisEstReg` CHAR(1) NOT NULL DEFAULT '1' COMMENT 'Estado registro',
  PRIMARY KEY (`HisCod`),
  INDEX `IDX_HIS_tri` (`HisTri` ASC) VISIBLE,
  INDEX `IDX_HIS_anio` (`HisAnio` ASC) VISIBLE,
  INDEX `IDX_HIS_arch` (`HisFecArch` ASC) VISIBLE,
  CONSTRAINT `FK_HIS_TRI`
    FOREIGN KEY (`HisTri`)
    REFERENCES `catastro_db`.`pat_tributo_cab` (`TriCod`)
    ON DELETE RESTRICT
    ON UPDATE CASCADE)
ENGINE = InnoDB
DEFAULT CHARACTER SET = utf8mb4
COLLATE = utf8mb4_spanish_ci
COMMENT = 'Historial Tributario – snapshot de tributos pagados/archivados';


-- -----------------------------------------------------
-- Table `catastro_db`.`pat_tributo_det`
-- -----------------------------------------------------
DROP TABLE IF EXISTS `catastro_db`.`pat_tributo_det` ;

CREATE TABLE IF NOT EXISTS `catastro_db`.`pat_tributo_det` (
  `TriDetCod` INT NOT NULL AUTO_INCREMENT COMMENT 'Código Detalle – PK (N,8)',
  `TriCod` INT NOT NULL COMMENT 'Tributo Cabecera [FK → PAT_TRIBUTO_CAB]',
  `TriDetViv` VARCHAR(10) NOT NULL COMMENT 'Predio del detalle [FK → C3M_VIVIENDA]',
  `TriDetMon` DECIMAL(10,2) NOT NULL DEFAULT '0.00' COMMENT 'Monto tributo del predio S/',
  `TriDetEstReg` CHAR(1) NOT NULL DEFAULT '1' COMMENT 'Estado registro',
  PRIMARY KEY (`TriDetCod`),
  INDEX `IDX_TRIDET_cab` (`TriCod` ASC) VISIBLE,
  INDEX `IDX_TRIDET_viv` (`TriDetViv` ASC) VISIBLE,
  CONSTRAINT `FK_TRIDET_CAB`
    FOREIGN KEY (`TriCod`)
    REFERENCES `catastro_db`.`pat_tributo_cab` (`TriCod`)
    ON DELETE RESTRICT
    ON UPDATE CASCADE,
  CONSTRAINT `FK_TRIDET_VIV`
    FOREIGN KEY (`TriDetViv`)
    REFERENCES `catastro_db`.`c3m_vivienda` (`VivCod`)
    ON DELETE RESTRICT
    ON UPDATE CASCADE)
ENGINE = InnoDB
DEFAULT CHARACTER SET = utf8mb4
COLLATE = utf8mb4_spanish_ci
COMMENT = 'Tributo Detalle – una línea por predio del tributo';


-- -----------------------------------------------------
-- Table `catastro_db`.`pbm_presupuesto_anual`
-- -----------------------------------------------------
DROP TABLE IF EXISTS `catastro_db`.`pbm_presupuesto_anual` ;

CREATE TABLE IF NOT EXISTS `catastro_db`.`pbm_presupuesto_anual` (
  `PreCod` INT NOT NULL AUTO_INCREMENT COMMENT 'Código Presupuesto – PK (N,8)',
  `PreMun` INT NOT NULL COMMENT 'Municipalidad [FK → C1M_MUNICIPALIDAD]',
  `PreAnio` YEAR NOT NULL COMMENT 'Año presupuestal (>2000)',
  `PreMonEst` DECIMAL(14,2) NOT NULL DEFAULT '0.00' COMMENT 'Proyección de ingresos por tributos S/ (>0)',
  `PreMonPag` DECIMAL(14,2) NOT NULL DEFAULT '0.00' COMMENT 'Total efectivamente recaudado S/ (>=0)',
  `PreMonGas` DECIMAL(14,2) NOT NULL DEFAULT '0.00' COMMENT 'Total de gastos aprobados S/ (>=0)',
  `PreFecApr` DATE NULL DEFAULT NULL COMMENT 'Fecha de aprobación del presupuesto',
  `PreEstReg` CHAR(1) NOT NULL DEFAULT '1' COMMENT 'Estado registro',
  PRIMARY KEY (`PreCod`),
  UNIQUE INDEX `UQ_PRE_MUN_ANIO` (`PreMun` ASC, `PreAnio` ASC) VISIBLE,
  INDEX `IDX_PRE_mun` (`PreMun` ASC) VISIBLE,
  INDEX `IDX_PRE_anio` (`PreAnio` ASC) VISIBLE,
  INDEX `IDX_PRE_mun_anio` (`PreMun` ASC, `PreAnio` ASC) VISIBLE,
  CONSTRAINT `FK_PRE_MUN`
    FOREIGN KEY (`PreMun`)
    REFERENCES `catastro_db`.`c1m_municipalidad` (`MunCod`)
    ON DELETE RESTRICT
    ON UPDATE CASCADE)
ENGINE = InnoDB
DEFAULT CHARACTER SET = utf8mb4
COLLATE = utf8mb4_spanish_ci
COMMENT = 'Maestro Presupuesto Anual – uno por municipio/año';


-- -----------------------------------------------------
-- Table `catastro_db`.`pbm_tributo_presupuesto`
-- -----------------------------------------------------
DROP TABLE IF EXISTS `catastro_db`.`pbm_tributo_presupuesto` ;

CREATE TABLE IF NOT EXISTS `catastro_db`.`pbm_tributo_presupuesto` (
  `TpPre` INT NOT NULL COMMENT 'Presupuesto [FK → PBM_PRESUPUESTO_ANUAL] (PK1)',
  `TpTri` INT NOT NULL COMMENT 'Tributo [FK → PAT_TRIBUTO_CAB] (PK2)',
  `TpMonAporte` DECIMAL(14,2) NOT NULL DEFAULT '0.00' COMMENT 'Monto aportado al presupuesto S/ (>=0)',
  `TpFecReg` DATE NOT NULL COMMENT 'Fecha de vinculación al presupuesto',
  `TpEstReg` CHAR(1) NOT NULL DEFAULT '1' COMMENT 'Estado registro',
  PRIMARY KEY (`TpPre`, `TpTri`),
  INDEX `IDX_TP_tri` (`TpTri` ASC) VISIBLE,
  CONSTRAINT `FK_TP_PRE`
    FOREIGN KEY (`TpPre`)
    REFERENCES `catastro_db`.`pbm_presupuesto_anual` (`PreCod`)
    ON DELETE RESTRICT
    ON UPDATE CASCADE,
  CONSTRAINT `FK_TP_TRI`
    FOREIGN KEY (`TpTri`)
    REFERENCES `catastro_db`.`pat_tributo_cab` (`TriCod`)
    ON DELETE RESTRICT
    ON UPDATE CASCADE)
ENGINE = InnoDB
DEFAULT CHARACTER SET = utf8mb4
COLLATE = utf8mb4_spanish_ci
COMMENT = 'Intermedia Tributo-Presupuesto – qué tributos componen cada presupuesto anual';


-- -----------------------------------------------------
-- Table `catastro_db`.`pcm_reportes_pre`
-- -----------------------------------------------------
DROP TABLE IF EXISTS `catastro_db`.`pcm_reportes_pre` ;

CREATE TABLE IF NOT EXISTS `catastro_db`.`pcm_reportes_pre` (
  `RepCod` INT NOT NULL AUTO_INCREMENT COMMENT 'Código Reporte Maestro – PK (N,8)',
  `RepMun` INT NOT NULL COMMENT 'Municipalidad [FK → C1M_MUNICIPALIDAD]',
  `RepZon` INT NULL DEFAULT NULL COMMENT 'Zona opcional [FK → C2M_ZONA] NULL=todo el municipio',
  `RepTip` VARCHAR(4) NOT NULL COMMENT 'Tipo: RPT1=Tributos RPT2=Presupuesto (A,4)',
  `RepTitulo` VARCHAR(120) NOT NULL COMMENT 'Título descriptivo del reporte (A,120)',
  `RepPer` YEAR NOT NULL COMMENT 'Período/año del reporte (>2000)',
  `RepFecGen` DATE NOT NULL COMMENT 'Fecha de generación',
  `RepEstReg` CHAR(1) NOT NULL DEFAULT '1' COMMENT 'Estado registro',
  PRIMARY KEY (`RepCod`),
  INDEX `IDX_REP_mun` (`RepMun` ASC) VISIBLE,
  INDEX `IDX_REP_zon` (`RepZon` ASC) VISIBLE,
  INDEX `IDX_REP_tip` (`RepTip` ASC) VISIBLE,
  INDEX `IDX_REP_per` (`RepPer` ASC) VISIBLE,
  CONSTRAINT `FK_REP_MUN`
    FOREIGN KEY (`RepMun`)
    REFERENCES `catastro_db`.`c1m_municipalidad` (`MunCod`)
    ON DELETE RESTRICT
    ON UPDATE CASCADE,
  CONSTRAINT `FK_REP_ZON`
    FOREIGN KEY (`RepZon`)
    REFERENCES `catastro_db`.`c2m_zona` (`ZonCod`)
    ON DELETE SET NULL
    ON UPDATE CASCADE)
ENGINE = InnoDB
DEFAULT CHARACTER SET = utf8mb4
COLLATE = utf8mb4_spanish_ci
COMMENT = 'Maestro Reportes – FK zona SET NULL para reportes a nivel municipio';


-- -----------------------------------------------------
-- Table `catastro_db`.`pct_reportes_cab`
-- -----------------------------------------------------
DROP TABLE IF EXISTS `catastro_db`.`pct_reportes_cab` ;

CREATE TABLE IF NOT EXISTS `catastro_db`.`pct_reportes_cab` (
  `RepCabCod` INT NOT NULL AUTO_INCREMENT COMMENT 'Código Reporte Cabecera – PK (N,8)',
  `RepCabRep` INT NOT NULL COMMENT 'Reporte Maestro [FK → PCM_REPORTES_PRE]',
  `RepCabPre` INT NULL DEFAULT NULL COMMENT 'Presupuesto asociado [FK → PBM_PRESUPUESTO_ANUAL]',
  `RepCabFec` DATE NOT NULL COMMENT 'Fecha del reporte cabecera',
  `RepCabTotTri` DECIMAL(14,2) NOT NULL DEFAULT '0.00' COMMENT 'Total tributos del período S/',
  `RepCabTotRec` DECIMAL(14,2) NOT NULL DEFAULT '0.00' COMMENT 'Total recaudado S/',
  `RepCabObs` VARCHAR(200) NULL DEFAULT NULL COMMENT 'Observaciones (A,200)',
  `RepCabEstReg` CHAR(1) NOT NULL DEFAULT '1' COMMENT 'Estado registro',
  PRIMARY KEY (`RepCabCod`),
  INDEX `IDX_REPCAB_rep` (`RepCabRep` ASC) VISIBLE,
  INDEX `IDX_REPCAB_pre` (`RepCabPre` ASC) VISIBLE,
  CONSTRAINT `FK_REPCAB_PRE`
    FOREIGN KEY (`RepCabPre`)
    REFERENCES `catastro_db`.`pbm_presupuesto_anual` (`PreCod`)
    ON DELETE SET NULL
    ON UPDATE CASCADE,
  CONSTRAINT `FK_REPCAB_REP`
    FOREIGN KEY (`RepCabRep`)
    REFERENCES `catastro_db`.`pcm_reportes_pre` (`RepCod`)
    ON DELETE RESTRICT
    ON UPDATE CASCADE)
ENGINE = InnoDB
DEFAULT CHARACTER SET = utf8mb4
COLLATE = utf8mb4_spanish_ci
COMMENT = 'Reporte Cabecera – resumen por municipio/zona con totales';


-- -----------------------------------------------------
-- Table `catastro_db`.`pch_reportes_cab`
-- -----------------------------------------------------
DROP TABLE IF EXISTS `catastro_db`.`pch_reportes_cab` ;

CREATE TABLE IF NOT EXISTS `catastro_db`.`pch_reportes_cab` (
  `HRepCabCod` INT NOT NULL AUTO_INCREMENT COMMENT 'Código Historial Rep.Cab – PK (N,8)',
