  `HRepCabTotRec` DECIMAL(14,2) NOT NULL DEFAULT '0.00' COMMENT 'Total recaudado al archivar S/',
  `HRepCabObs` VARCHAR(200) NULL DEFAULT NULL COMMENT 'Observaciones (A,200)',
  `HRepCabEstReg` CHAR(1) NOT NULL DEFAULT '1' COMMENT 'Estado registro',
  PRIMARY KEY (`HRepCabCod`),
  INDEX `IDX_HREPCAB_ori` (`HRepCabOri` ASC) VISIBLE,
  INDEX `IDX_HREPCAB_arch` (`HRepCabFecArch` ASC) VISIBLE,
