COLLATE = utf8mb4_spanish_ci
COMMENT = 'Historial Reporte Cabecera – versiones archivadas con snapshot de montos';


-- -----------------------------------------------------
-- Table `catastro_db`.`pct_reportes_det`
-- -----------------------------------------------------
DROP TABLE IF EXISTS `catastro_db`.`pct_reportes_det` ;

CREATE TABLE IF NOT EXISTS `catastro_db`.`pct_reportes_det` (
  `RepDetCod` INT NOT NULL AUTO_INCREMENT COMMENT 'Código Reporte Detalle – PK (N,8)',
