DROP TABLE IF EXISTS `catastro_db`.`pch_reportes_det` ;

CREATE TABLE IF NOT EXISTS `catastro_db`.`pch_reportes_det` (
  `HRepDetCod` INT NOT NULL AUTO_INCREMENT COMMENT 'Código Historial Rep.Det – PK (N,8)',
  `HRepDetCab` INT NOT NULL COMMENT 'Historial Rep.Cab [FK → PCH_REPORTES_CAB]',
  `HRepDetOri` INT NULL DEFAULT NULL COMMENT 'Detalle original [FK → PCT_REPORTES_DET]',
  `HRepDetMonCal` DECIMAL(14,2) NOT NULL DEFAULT '0.00' COMMENT 'Monto calculado al archivar S/',
  `HRepDetMonPag` DECIMAL(14,2) NOT NULL DEFAULT '0.00' COMMENT 'Monto pagado al archivar S/',
  `HRepDetEstReg` CHAR(1) NOT NULL DEFAULT '1' COMMENT 'Estado registro',
  PRIMARY KEY (`HRepDetCod`),
  INDEX `IDX_HREPDET_cab` (`HRepDetCab` ASC) VISIBLE,
  INDEX `IDX_HREPDET_ori` (`HRepDetOri` ASC) VISIBLE,
  CONSTRAINT `FK_HREPDET_CAB`
    FOREIGN KEY (`HRepDetCab`)
    REFERENCES `catastro_db`.`pch_reportes_cab` (`HRepCabCod`)
    ON DELETE RESTRICT
    ON UPDATE CASCADE,
  CONSTRAINT `FK_HREPDET_ORI`
    FOREIGN KEY (`HRepDetOri`)
    REFERENCES `catastro_db`.`pct_reportes_det` (`RepDetCod`)
    ON DELETE SET NULL
    ON UPDATE CASCADE)
ENGINE = InnoDB
DEFAULT CHARACTER SET = utf8mb4
COLLATE = utf8mb4_spanish_ci
COMMENT = 'Historial Reporte Detalle – líneas archivadas con snapshot de montos';


